// .create-or-alter materialized-view with (backfill=true) lastDatesConfig on table datesConfig {
//     datesConfig
//     | summarize startDate = max(startDate) by model, tableName, scope
// }
.create-or-alter materialized-view with (backfill=true) lastDatesConfig 
on table datesConfig 
{
    datesConfig
    | summarize arg_max(timestamp, startDate) 
        by model, tableName, scope
}

.alter table processExecutionLog folder "log"

lastDatesConfig

.set-or-replace datesConfig_tmp  <|
datesConfig
| extend timestamp = ingestion_time()

.drop table datesConfig
.rename table datesConfig_tmp to datesConfig
